@app.post("/agent/approval-checkpoint/pause")
def agent_approval_checkpoint_pause(payload):
    checkpoint_id = f"chk_{uuid.uuid4().hex[:16]}"
    expires_at = (datetime.now(timezone.utc) + timedelta(minutes=max(1, min(payload.ttl_minutes, 240)))).isoformat()
    row = ApprovalCheckpoint(..., status="paused", expires_at=expires_at)
    attempt.status = InstallAttemptStatus.approval_required
    attempt.install_status = "paused_for_approval"
    return {"ok": True, "checkpoint_id": checkpoint_id, "status": "paused", "expires_at": expires_at}

rollback_receipt.excerpt:
@app.post("/agent/rollback")
def agent_rollback(payload):
    attempt.rollback_status = "rolled_back"
    attempt.install_status = "rolled_back"
    attempt.activation_status = "deactivated"
    attempt.status = InstallAttemptStatus.rolled_back
    receipt = {
      "attempt_id": attempt.attempt_id,
      "rollback_status": attempt.rollback_status,
      "reason": payload.reason,
      "runtime_id": attempt.runtime_id,
      "install_target": attempt.install_target,
      "activation_mode": attempt.activation_mode
    }
    return {"ok": True, "rollback_receipt": receipt}

